            'max_score': group_data['max_score'],
            'min_score': group_data['min_score']
        }

        # Apply custom aggregation functions if provided
        if aggregation_funcs:
            custom_stats = {}
            for field_name, func in aggregation_funcs.items():
                # Get field values for this group
                field_values = group_data['custom_fields'].get(field_name, [])

                # Handle empty fields
                if not field_values:
                    custom_stats[field_name] = None
                else:
                    try:
                        custom_stats[field_name] = func(field_values)
                    except Exception:
                        custom_stats[field_name] = None

            # Merge custom statistics with default stats
            stats.update(custom_stats)

        final_results[group_value] = stats

    return final_results
